INSERT INTO products (id, title, slug, brand, description, status, stock, price, created_at, updated_at) VALUES ('cac536b1-3c06-4eb5-a31f-2ddbe9b881ec', 'Surgeons Cap', 'surgeons-cap-ddy6', 'BestQ Medical', 'Surgeons Cap adalah alat pelindung medis yang digunakan untuk menutupi rambut dan kulit kepala guna membantu menjaga kebersihan area kerja serta mengurangi risiko kontaminasi selama tindakan medis maupun nonmedis. Produk ini cocok digunakan di rumah sakit, klinik, laboratorium, ruang operasi, industri makanan, hingga berbagai lingkungan kerja yang membutuhkan standar kebersihan tinggi.
Terbuat dari bahan non woven berkualitas dengan keunggulan:
• Ringan sehingga nyaman digunakan dalam waktu yang lama.
• Memiliki sirkulasi udara yang baik sehingga kepala tetap terasa nyaman saat digunakan.
• Desain elastis sehingga mudah dikenakan dan menyesuaikan berbagai ukuran kepala.
• Membantu menahan rambut agar tetap rapi selama beraktivitas.
• Sekali pakai sehingga lebih higienis dan praktis digunakan.
• Bahan lembut sehingga tidak mudah menyebabkan iritasi pada kulit kepala.

Cara penggunaan mudah:
Ambil Surgeons Cap dari kemasan, bentangkan bagian elastis, lalu kenakan hingga seluruh rambut tertutup dengan rapi. Pastikan penutup kepala terpasang dengan baik sebelum memulai aktivitas, kemudian buang setelah selesai digunakan sesuai prosedur pembuangan yang berlaku.', 'published', 0, 0, 1783936121214, 1783936121214);
INSERT INTO products (id, title, slug, brand, description, status, stock, price, created_at, updated_at) VALUES ('c3f71a1b-cdc8-40ea-9ead-b9abdd13a793', 'Surgical Mask', 'surgical-mask-twsb', 'BestQ Medical', 'Surgical Mask adalah alat pelindung diri yang digunakan untuk membantu mengurangi paparan droplet, debu, dan partikel dari lingkungan sekitar serta membantu menjaga kebersihan selama beraktivitas. Produk ini cocok digunakan di rumah sakit, klinik, laboratorium, fasilitas pelayanan kesehatan, maupun untuk penggunaan sehari-hari yang memerlukan perlindungan tambahan.
Terbuat dari bahan non woven berkualitas dengan keunggulan:
• Memiliki beberapa lapisan filtrasi sehingga membantu menyaring partikel dan droplet secara optimal.
• Bahan lembut sehingga nyaman digunakan dalam waktu yang lama.
• Breathable sehingga sirkulasi udara tetap baik dan memudahkan bernapas.
• Earloop elastis sehingga nyaman di telinga dan tidak mudah lepas saat digunakan.
• Nose clip yang dapat disesuaikan sehingga masker lebih pas di wajah dan membantu meminimalkan celah.
• Sekali pakai sehingga lebih higienis dan praktis untuk penggunaan harian.

Cara penggunaan mudah:
Buka masker dari kemasan, pasang dengan menempatkan earloop pada kedua telinga, lalu sesuaikan nose clip agar mengikuti bentuk hidung dan pastikan masker menutupi hidung, mulut, serta dagu dengan rapat. Buang masker setelah digunakan sesuai prosedur pembuangan yang berlaku.', 'published', 0, 0, 1783936121214, 1783936121214);
INSERT INTO products (id, title, slug, brand, description, status, stock, price, created_at, updated_at) VALUES ('e10a414e-ce0d-4c06-ab1e-95164e6a3ebf', 'Surgical Gown', 'surgical-gown-pimt', 'BestQ Medical', 'Surgical Gown adalah alat pelindung diri yang digunakan untuk membantu melindungi tubuh dan pakaian dari paparan cairan, percikan, serta kontaminan selama tindakan medis maupun aktivitas yang memerlukan standar kebersihan tinggi. Produk ini cocok digunakan di rumah sakit, klinik, laboratorium, ruang operasi, hingga berbagai lingkungan kerja yang mengutamakan perlindungan dan higienitas.
Terbuat dari bahan non woven berkualitas dengan keunggulan:
• Memberikan perlindungan terhadap percikan cairan sehingga membantu mengurangi risiko kontaminasi.
• Bahan ringan sehingga nyaman digunakan dalam waktu yang lama.
• Breathable sehingga sirkulasi udara tetap terjaga dan tidak mudah terasa gerah.
• Desain lengan panjang dengan manset elastis sehingga memberikan perlindungan yang lebih optimal.
• Tali pengikat pada leher dan pinggang sehingga mudah disesuaikan dengan berbagai ukuran tubuh.
• Sekali pakai sehingga lebih higienis dan praktis untuk berbagai kebutuhan medis maupun nonmedis.

Cara penggunaan mudah: 
Keluarkan Surgical Gown dari kemasan, kenakan dengan memasukkan kedua lengan ke dalam lengan baju, lalu ikat tali pada bagian leher dan pinggang hingga pas dan nyaman digunakan. Lepaskan dengan hati-hati setelah selesai digunakan dan buang sesuai prosedur pembuangan yang berlaku.', 'published', 0, 0, 1783936121214, 1783936121214);
